			noShares:           17,
		},
		{
			Name: "SecondBetYesDirection",
			Bets: []models.Bet{
				makeDBPMBet(20, "NO", "one", 0),
				makeDBPMBet(10, "YES", "two", 1),
			},
			ProbabilityChanges: modelstesting.GenerateProbability(0.500, 0.167, 0.375),
